import{_ as e,a as i,b as o,c as r,d as t,e as s,f as d,g as n}from"./chunks/无关系记录重新申请.D_1qirb1.js";import{_ as l,o as c,c as p,a2 as u}from"./chunks/framework.DnrXFDHb.js";const x=JSON.parse('{"title":"Índice distribuido federado","description":"","frontmatter":{},"headers":[],"relativePath":"es/Other/federated-distributed-index.md","filePath":"es/Other/federated-distributed-index.md","lastUpdated":1781962217000}'),h={name:"es/Other/federated-distributed-index.md"};function m(b,a,v,g,f,q){return c(),p("div",null,[...a[0]||(a[0]=[u('<h1 id="indice-distribuido-federado" tabindex="-1">Índice distribuido federado <a class="header-anchor" href="#indice-distribuido-federado" aria-label="Permalink to &quot;Índice distribuido federado&quot;">​</a></h1><p>El índice distribuido federado permite que varios sitios ImgBed compartan listas de archivos entre sí.</p><p>En pocas palabras:</p><ul><li>Puedes compartir algunas carpetas de tu sitio con otras personas.</li><li>Puedes unirte al nodo de otra persona y sincronizar su lista compartida en tu panel.</li><li>Los archivos federados sirven para explorar, buscar, previsualizar y copiar enlaces. No se vuelven a subir a tu propio almacenamiento.</li></ul><h2 id="donde-se-configura" tabindex="-1">Dónde se configura <a class="header-anchor" href="#donde-se-configura" aria-label="Permalink to &quot;Dónde se configura&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Configuración del sistema -&gt; Otros ajustes -&gt; Índice distribuido federado</span></span></code></pre></div><p><img src="'+e+`" alt="Nodo local" loading="lazy"></p><p>La página tiene tres pestañas:</p><table tabindex="0"><thead><tr><th>Pestaña</th><th>Uso</th></tr></thead><tbody><tr><td>Nodo local</td><td>Configurar tu nodo, dominio público, carpetas compartidas e índice saliente</td></tr><tr><td>Nodos unidos</td><td>Gestionar los nodos de otros sitios a los que te uniste</td></tr><tr><td>Solicitudes a mi nodo</td><td>Gestionar solicitudes de otras personas para unirse a tu nodo</td></tr></tbody></table><h2 id="configuracion-inicial" tabindex="-1">Configuración inicial <a class="header-anchor" href="#configuracion-inicial" aria-label="Permalink to &quot;Configuración inicial&quot;">​</a></h2><ol><li>Abre <code>Nodo local</code>.</li><li>Activa <code>Habilitar</code>.</li><li>Elige las carpetas que quieres compartir en <code>Carpetas de sincronización</code>.</li><li>Haz clic en <code>Actualizar índice saliente</code>.</li><li>Si ImgBed detecta un cambio de dominio, confirma que el dominio actual es el dominio real de producción.</li></ol><p>Puedes seleccionar varias carpetas. Si dejas la lista vacía, se comparten todas las carpetas.</p><h2 id="nodo-local" tabindex="-1">Nodo local <a class="header-anchor" href="#nodo-local" aria-label="Permalink to &quot;Nodo local&quot;">​</a></h2><h3 id="dominio-publico" tabindex="-1">Dominio público <a class="header-anchor" href="#dominio-publico" aria-label="Permalink to &quot;Dominio público&quot;">​</a></h3><p>El dominio público es la dirección que otros nodos usan para acceder a tu sitio.</p><p>ImgBed lo detecta automáticamente, así que normalmente no hace falta escribirlo. Al actualizar el índice por primera vez, o después de cambiar de dominio, pedirá confirmación.</p><h3 id="carpetas-de-sincronizacion" tabindex="-1">Carpetas de sincronización <a class="header-anchor" href="#carpetas-de-sincronizacion" aria-label="Permalink to &quot;Carpetas de sincronización&quot;">​</a></h3><p>Estas carpetas deciden qué archivos se comparten.</p><p>Por ejemplo:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/</span></span>
<span class="line"><span>/2/</span></span></code></pre></div><p>En este caso, otros nodos solo verán archivos dentro de esos dos directorios.</p><h3 id="actualizar-indice-saliente" tabindex="-1">Actualizar índice saliente <a class="header-anchor" href="#actualizar-indice-saliente" aria-label="Permalink to &quot;Actualizar índice saliente&quot;">​</a></h3><p>Este botón actualiza la lista de archivos que otros nodos pueden sincronizar desde tu sitio.</p><p>Úsalo cuando:</p><ul><li>Activas la federación por primera vez.</li><li>Subes nuevos archivos que quieres compartir.</li><li>Cambias las carpetas compartidas.</li><li>Cambias el dominio público y necesitas confirmarlo.</li></ul><h2 id="unirse-a-otros-nodos" tabindex="-1">Unirse a otros nodos <a class="header-anchor" href="#unirse-a-otros-nodos" aria-label="Permalink to &quot;Unirse a otros nodos&quot;">​</a></h2><p><code>Nodos unidos</code> es el lugar donde te suscribes a nodos de otros sitios ImgBed.</p><p><img src="`+i+'" alt="Nodos unidos" loading="lazy"></p><ol><li>Pide al propietario del otro nodo un enlace de invitación.</li><li>Pégalo en el cuadro de entrada.</li><li>Haz clic en <code>Solicitar unión</code>.</li><li>Espera a que la otra parte lo apruebe en su panel.</li></ol><p>Después de la aprobación, usa <code>Actualizar índice entrante</code> para sincronizar los archivos compartidos.</p><p>Si solo quieres actualizar un nodo concreto, usa <code>Actualizar índice</code> en la tarjeta de ese nodo.</p><p><img src="'+o+'" alt="Actualizar índice" loading="lazy"></p><h2 id="gestionar-solicitudes-a-tu-nodo" tabindex="-1">Gestionar solicitudes a tu nodo <a class="header-anchor" href="#gestionar-solicitudes-a-tu-nodo" aria-label="Permalink to &quot;Gestionar solicitudes a tu nodo&quot;">​</a></h2><p><code>Solicitudes a mi nodo</code> muestra las personas que quieren unirse a tu nodo.</p><p><img src="'+r+'" alt="Solicitudes a mi nodo" loading="lazy"></p><p>Para generar una invitación, asegúrate de que el nodo local esté habilitado, ejecuta al menos una vez <code>Actualizar índice saliente</code> para confirmar el dominio público y luego pulsa <code>Restablecer enlace de invitación</code>.</p><p>Cuando llega una solicitud, puedes elegir:</p><table tabindex="0"><thead><tr><th>Acción</th><th>Resultado</th></tr></thead><tbody><tr><td>Aprobar</td><td>Permite que la otra parte sincronice tu lista compartida</td></tr><tr><td>Rechazar</td><td>No permite la unión</td></tr><tr><td>Eliminar</td><td>Borra un registro terminado</td></tr><tr><td>Comprobar estado</td><td>Verifica si la otra parte conserva la relación</td></tr></tbody></table><p>Después de aprobar, la otra parte todavía debe actualizar su índice entrante para ver tus archivos.</p><p><img src="'+t+'" alt="Aprobar nodo" loading="lazy"></p><h2 id="mensajes" tabindex="-1">Mensajes <a class="header-anchor" href="#mensajes" aria-label="Permalink to &quot;Mensajes&quot;">​</a></h2><p>Cuando la relación ya está aprobada, puedes usar <code>Mensaje</code> en la tarjeta del nodo.</p><p>Los mensajes solo sirven para coordinar la relación federada. No cambian archivos, etiquetas, directorios ni permisos.</p><p><img src="'+s+'" alt="Mensajes" loading="lazy"></p><h2 id="ver-archivos-federados" tabindex="-1">Ver archivos federados <a class="header-anchor" href="#ver-archivos-federados" aria-label="Permalink to &quot;Ver archivos federados&quot;">​</a></h2><p>Cuando la sincronización termine, vuelve a la lista de archivos del panel. En la parte superior puedes cambiar entre archivos locales y archivos federados.</p><p>Los archivos federados no son archivos locales: puedes verlos, buscarlos, previsualizarlos y copiar enlaces, pero no moverlos, borrarlos, cambiarles etiquetas ni crear copias de seguridad desde tu sitio.</p><p><img src="'+d+'" alt="Vista en el panel" loading="lazy"></p><h2 id="preguntas-habituales" tabindex="-1">Preguntas habituales <a class="header-anchor" href="#preguntas-habituales" aria-label="Permalink to &quot;Preguntas habituales&quot;">​</a></h2><h3 id="aparece-que-no-existe-relacion" tabindex="-1">Aparece que no existe relación <a class="header-anchor" href="#aparece-que-no-existe-relacion" aria-label="Permalink to &quot;Aparece que no existe relación&quot;">​</a></h3><p>Normalmente significa que la otra parte eliminó tu registro. En ese caso debes enviar una nueva solicitud.</p><p><img src="'+n+'" alt="Solicitar de nuevo" loading="lazy"></p><h3 id="me-uni-pero-no-veo-archivos" tabindex="-1">Me uní pero no veo archivos <a class="header-anchor" href="#me-uni-pero-no-veo-archivos" aria-label="Permalink to &quot;Me uní pero no veo archivos&quot;">​</a></h3><p>Comprueba:</p><ol><li>La otra parte aprobó tu solicitud.</li><li>La otra parte actualizó su índice saliente.</li><li>Tú actualizaste el índice entrante.</li><li>Las carpetas sincronizadas de la otra parte contienen los directorios que quiere compartir.</li></ol>',55)])])}const P=l(h,[["render",m]]);export{x as __pageData,P as default};
